      "content": "const fs = require('fs');
const path = require('path');

const DATA_PATH = path.join(__dirname, '../../data/problems.json');

function loadProblems() {
  const raw = fs.readFileSync(DATA_PATH, 'utf-8');
  return JSON.parse(raw);
}

function getDifficultyBreakdown(problems) {
  const breakdown = {};
  for (const p of problems) {
    if (!breakdown[p.difficulty]) breakdown[p.difficulty] = 0;
    breakdown[p.difficulty]++;
  }
  return breakdown;
}

function getComponentLanguages(problems) {
  const langsSet = new Set();
  for (const p of problems) {
    if (Array.isArray(p.componentLanguages)) {
      for (const lang of p.componentLanguages) {
        langsSet.add(lang);
      }
    }
  }
  return Array.from(langsSet).sort();
}

async function listProblems({ difficulty, includeComponents, limit = 50 }) {
  let problems = loadProblems();

  // Filter by difficulty if provided
  if (difficulty) {
    problems = problems.filter(p => p.difficulty === difficulty);
  }

  const totalProblems = loadProblems().length;
  const filteredCount = problems.length;

  // Sort by roundId ascending
  problems.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Limit results to max 50
  const appliedLimit = Math.min(limit, 50);
  problems = problems.slice(0, appliedLimit);

  // Compose response
  const difficultyBreakdown = getDifficultyBreakdown(loadProblems());

  const response = {
    totalProblems,
    filteredCount,
    appliedLimit,
    difficultyBreakdown
  };

  if (includeComponents) {
    response.componentLanguages = getComponentLanguages(problems);
  }

  response.problems = problems;

  return response;
}

module.exports = {
  listProblems
};
