async function listProblems(req, res) {
  try {
    const difficulty = req.query.difficulty || undefined;
    const includeComponents = req.query.includeComponents === 'true';
    const limit = req.query.limit ? parseInt(req.query.limit, 10) : 50;

    const result = await ProblemsService.listProblems({ difficulty, includeComponents, limit });

    res.status(200).json(result);
  } catch (err) {
    res.status(500).json({ error: 'Internal Server Error' });
  }
}

module.exports = {
  listProblems
};
